import mongoose from 'mongoose';

export const connectDB = async () => {
  try {
    const conn = await mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/investiq_ai');
    console.log(`MongoDB Connected: ${conn.connection.host}`);
  } catch (error) {
    console.error(`Error connecting to MongoDB: ${error.message}`);
    // Do not crash the server in local dev if MongoDB isn't running immediately,
    // so we can still demonstrate mock fallback mode
    console.warn('Proceeding with MongoDB fallback. Database operations will fail gracefully.');
  }
};

import mongoose from 'mongoose';

const CompetitorSchema = new mongoose.Schema({
  name: { type: String, required: true },
  marketCap: { type: String, required: true },
  strengths: { type: String, required: true }
});

const SourceSchema = new mongoose.Schema({
  title: { type: String, required: true },
  url: { type: String, required: true }
});

const SwotSchema = new mongoose.Schema({
  strengths: [{ type: String }],
  weaknesses: [{ type: String }],
  opportunities: [{ type: String }],
  threats: [{ type: String }]
});

const ReportSchema = new mongoose.Schema({
  companyName: { type: String, required: true },
  recommendation: { 
    type: String, 
    enum: ['Invest', 'Consider', 'Pass'], 
    required: true 
  },
  score: { type: Number, required: true },
  summary: { type: String, required: true },
  financialHealth: { type: String, required: true },
  growthDrivers: [{ type: String }],
  risks: [{ type: String }],
  swot: { type: SwotSchema, required: true },
  competitors: [CompetitorSchema],
  sources: [SourceSchema],
  createdAt: { type: Date, default: Date.now }
});

const Report = mongoose.model('Report', ReportSchema);
export default Report;

