import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import axios from 'axios';
import { generateMockReport } from './mockService.js';

/**
 * Searches the web for information about a company using Tavily Search API.
 * @param {string} companyName 
 * @returns {Promise<Array<{title: string, url: string, content: string}>>}
 */
async function searchWeb(companyName) {
  const tavilyKey = process.env.TAVILY_API_KEY;
  if (!tavilyKey) {
    console.warn('TAVILY_API_KEY is missing. Skipping live web search.');
    return [];
  }

  try {
    const response = await axios.post('https://api.tavily.com/search', {
      api_key: tavilyKey,
      query: `${companyName} stock analysis, financial health, risks, competitors, and growth outlook`,
      search_depth: 'advanced',
      max_results: 6
    });

    return response.data.results || [];
  } catch (error) {
    console.error('Tavily Search API failed:', error.message);
    return [];
  }
}

/**
 * Performs investment research using Tavily Search and Gemini LLM.
 * @param {string} companyName 
 * @returns {Promise<object>} Structured research report
 */
export const performResearch = async (companyName) => {
  const geminiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_GENAI_API_KEY;

  if (!geminiKey) {
    console.warn('GEMINI_API_KEY or GOOGLE_GENAI_API_KEY is missing. Falling back to high-fidelity mock data.');
    return generateMockReport(companyName);
  }

  try {
    // 1. Search the web for live context
    console.log(`Gathering live market intelligence for: ${companyName}...`);
    const searchResults = await searchWeb(companyName);

    // If we have no search results, we can still proceed with Gemini's base knowledge,
    // but having search results enhances the analysis.
    const searchContext = searchResults.length > 0 
      ? searchResults.map((r, i) => `[Source ${i+1}]: ${r.title}\nURL: ${r.url}\nContent: ${r.content}\n---`).join('\n')
      : 'No live search results available. Perform analysis based on historical knowledge.';

    // 2. Initialize Gemini Chat model
    const model = new ChatGoogleGenerativeAI({
      apiKey: geminiKey,
      modelName: 'gemini-2.5-flash', // Fallback to gemini-1.5-flash if needed
      maxOutputTokens: 2048,
      temperature: 0.2,
    });

    const prompt = `You are a Senior Investment Research Analyst and a Venture Capitalist.
Your goal is to evaluate if "${companyName}" is a good investment opportunity.

Use the following live web search context collected about the company:
${searchContext}

Based on this context and your expertise, conduct a comprehensive investment analysis.
Return your output STRICTLY in JSON format. Do not wrap the JSON in markdown code blocks (\`\`\`json ... \`\`\`). Output only the raw valid JSON string.

The JSON structure must match the following schema:
{
  "companyName": "Full Company Name and Ticker (e.g. Apple Inc. (AAPL))",
  "recommendation": "Must be one of: 'Invest', 'Consider', or 'Pass'",
  "score": 85, // Numeric value from 0 to 100 representing confidence/viability
  "summary": "A concise 3-4 sentence investment thesis describing the core finding.",
  "financialHealth": "Detailed analysis of financial performance, debt, and cash positions.",
  "growthDrivers": [
    "Growth driver 1...",
    "Growth driver 2...",
    "Growth driver 3..."
  ],
  "risks": [
    "Key risk factor 1...",
    "Key risk factor 2...",
    "Key risk factor 3..."
  ],
  "swot": {
    "strengths": ["Strength 1", "Strength 2", "Strength 3"],
    "weaknesses": ["Weakness 1", "Weakness 2", "Weakness 3"],
    "opportunities": ["Opportunity 1", "Opportunity 2", "Opportunity 3"],
    "threats": ["Threat 1", "Threat 2", "Threat 3"]
  },
  "competitors": [
    {
      "name": "Competitor 1",
      "marketCap": "Market Cap of Competitor 1",
      "strengths": "Main competitive advantage of Competitor 1"
    },
    {
      "name": "Competitor 2",
      "marketCap": "Market Cap of Competitor 2",
      "strengths": "Main competitive advantage of Competitor 2"
    }
  ],
  "sources": [
    {
      "title": "Title of search source used",
      "url": "URL of search source used"
    }
  ]
}

Provide deep analysis, avoid boilerplate summaries, and ensure all sources used in the search are cited in the 'sources' array.`;

    console.log(`Analyzing data and generating investment thesis for: ${companyName}...`);

    // Request structured response
    const response = await model.invoke([
      { role: 'user', content: prompt }
    ]);

    let textResponse = response.content;
    if (typeof textResponse !== 'string') {
      textResponse = JSON.stringify(textResponse);
    }

    // Clean up code blocks if the model included them anyway
    let cleanedJson = textResponse.trim();
    if (cleanedJson.startsWith('```json')) {
      cleanedJson = cleanedJson.replace(/^```json/, '').replace(/```$/, '').trim();
    } else if (cleanedJson.startsWith('```')) {
      cleanedJson = cleanedJson.replace(/^```/, '').replace(/```$/, '').trim();
    }

    try {
      const parsedReport = JSON.parse(cleanedJson);

      // Ensure we have sources filled
      if (!parsedReport.sources || parsedReport.sources.length === 0) {
        parsedReport.sources = searchResults.map(r => ({
          title: r.title,
          url: r.url
        }));
      }

      return parsedReport;
    } catch (parseError) {
      console.error('Failed to parse Gemini JSON output. Raw output was:', cleanedJson);
      throw new Error('Invalid JSON format returned from Gemini model.');
    }
  } catch (error) {
    console.error('LangChain performance research failed:', error.message);
    console.warn('Falling back to high-fidelity mock data.');
    return generateMockReport(companyName);
  }
};

import Report from '../models/Report.js';
import { performResearch } from '../services/langchainService.js';

// Trigger AI Research for a company
export const analyzeCompany = async (req, res) => {
  const { companyName } = req.body;

  if (!companyName || typeof companyName !== 'string' || companyName.trim() === '') {
    return res.status(400).json({ error: 'Company name is required and must be a valid string.' });
  }

  try {
    const reportData = await performResearch(companyName);

    // Attempt to save to MongoDB
    let savedReport = reportData;
    try {
      const report = new Report(reportData);
      savedReport = await report.save();
    } catch (dbError) {
      console.warn('Could not save report to MongoDB (running in offline/local mode):', dbError.message);
      // We will still return the generated report so the application is fully functional offline
      // Let's add a temporary ID so the frontend can key off of it
      savedReport = { ...reportData, _id: 'temp_' + Date.now(), offline: true };
    }

    res.status(200).json(savedReport);
  } catch (error) {
    console.error('Error analyzing company:', error);
    res.status(500).json({ error: 'Failed to run investment analysis. Please try again.' });
  }
};

// Retrieve previously saved analysis history
export const getHistory = async (req, res) => {
  try {
    const history = await Report.find().sort({ createdAt: -1 }).limit(20);
    res.status(200).json(history);
  } catch (dbError) {
    console.warn('Could not retrieve reports from MongoDB (running in offline/local mode):', dbError.message);
    // Return empty list if database is unavailable
    res.status(200).json([]);
  }
};

import express from 'express';
import { analyzeCompany, getHistory } from '../controllers/researchController.js';

const router = express.Router();

// Route to perform new research
router.post('/analyze', analyzeCompany);

// Route to get historical reports
router.get('/history', getHistory);

export default router;

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { connectDB } from './config/db.js';
import researchRoutes from './routes/researchRoutes.js';

// Load environment variables
dotenv.config();

const app = express();
const PORT = process.env.PORT || 5001;

// Middleware
app.use(cors());
app.use(express.json());

// Database connection
connectDB();

// API Routes
app.use('/api/research', researchRoutes);

// Health check endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'ok', service: 'InvestIQ AI API Server' });
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

