import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react(), tailwindcss()],
  server: {
    port: 3000,
    proxy: {
      '/api': {
        target: 'http://localhost:5001',
        changeOrigin: true,
      }
    }
  }
})

export interface Swot {
  strengths: string[];
  weaknesses: string[];
  opportunities: string[];
  threats: string[];
}

export interface Competitor {
  name: string;
  marketCap: string;
  strengths: string;
}

export interface Source {
  title: string;
  url: string;
}

export interface ResearchReport {
  _id?: string;
  companyName: string;
  recommendation: 'Invest' | 'Consider' | 'Pass';
  score: number;
  summary: string;
  financialHealth: string;
  growthDrivers: string[];
  risks: string[];
  swot: Swot;
  competitors: Competitor[];
  sources: Source[];
  createdAt?: string;
  offline?: boolean;
}

import axios from 'axios';
import { ResearchReport } from '../types';

const apiClient = axios.create({
  baseURL: '/api/research',
  headers: {
    'Content-Type': 'application/json',
  },
});

export const analyzeCompany = async (companyName: string): Promise<ResearchReport> => {
  const response = await apiClient.post<ResearchReport>('/analyze', { companyName });
  return response.data;
};

export const getHistory = async (): Promise<ResearchReport[]> => {
  const response = await apiClient.get<ResearchReport[]>('/history');
  return response.data;
};

