@import "tailwindcss";

:root {
  color-scheme: dark;
  background-color: #0b0f19;
  color: #f3f4f6;
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
}

body {
  margin: 0;
  padding: 0;
  min-height: 100vh;
  background: radial-gradient(circle at 50% 0%, #1e1b4b 0%, #0f172a 50%, #020617 100%);
  background-attachment: fixed;
  overflow-x: hidden;
}

#root {
  width: 100%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* Glassmorphism scrollbar */
::-webkit-scrollbar {
  width: 8px;
}
::-webkit-scrollbar-track {
  background: rgba(15, 23, 42, 0.5);
}
::-webkit-scrollbar-thumb {
  background: rgba(99, 102, 241, 0.3);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(99, 102, 241, 0.6);
}

/* Glass card styling helper */
.glass-panel {
  background: rgba(15, 23, 42, 0.45);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.37);
}

.glass-panel-glow {
  background: rgba(15, 23, 42, 0.6);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(99, 102, 241, 0.2);
  box-shadow: 0 0 25px rgba(99, 102, 241, 0.1);
}

import React from 'react';
import { TrendingUp, ShieldAlert, Cpu } from 'lucide-react';

interface DashboardHeaderProps {
  isOffline?: boolean;
}

export const DashboardHeader: React.FC<DashboardHeaderProps> = ({ isOffline }) => {
  return (
    <header className="glass-panel sticky top-0 z-50 px-6 py-4 flex items-center justify-between border-b border-white/5">
      <div className="flex items-center gap-3">
        <div className="p-2.5 bg-indigo-500/10 border border-indigo-500/25 rounded-xl shadow-inner shadow-indigo-500/20">
          <TrendingUp className="w-6 h-6 text-indigo-400" />
        </div>
        <div>
          <h1 className="text-xl font-bold tracking-tight text-white m-0 flex items-center gap-2">
            InvestIQ <span className="px-2 py-0.5 text-[10px] tracking-wide uppercase font-semibold bg-indigo-600/20 text-indigo-400 border border-indigo-500/30 rounded-md">Agent</span>
          </h1>
          <p className="text-xs text-slate-400">AI-Powered Investment Analyst</p>
        </div>
      </div>

      <div className="flex items-center gap-4">
        {isOffline ? (
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-amber-500/10 border border-amber-500/20 text-xs font-medium text-amber-400">
            <ShieldAlert className="w-3.5 h-3.5 animate-pulse" />
            <span>Sandbox Mode (API Simulation)</span>
          </div>
        ) : (
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-xs font-medium text-emerald-400">
            <Cpu className="w-3.5 h-3.5" />
            <span>AI Connected</span>
          </div>
        )}
      </div>
    </header>
  );
};

import React, { useState } from 'react';
import { Search, Sparkles } from 'lucide-react';
import { motion } from 'framer-motion';

interface ResearchFormProps {
  onSearch: (companyName: string) => void;
  isLoading: boolean;
}

const POPULAR_COMPANIES = ['Apple (AAPL)', 'Tesla (TSLA)', 'NVIDIA (NVDA)', 'Microsoft (MSFT)'];

export const ResearchForm: React.FC<ResearchFormProps> = ({ onSearch, isLoading }) => {
  const [query, setQuery] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim());
    }
  };

  const handleQuickSelect = (name: string) => {
    if (!isLoading) {
      setQuery(name);
      onSearch(name);
    }
  };

  return (
    <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl">
      <h2 className="text-lg font-semibold text-slate-100 mb-2 flex items-center gap-2">
        <Sparkles className="w-5 h-5 text-indigo-400" />
        Analyze Investment Opportunity
      </h2>
      <p className="text-sm text-slate-400 mb-6">
        Enter a company name or ticker. Our autonomous research agent will scan the live web, compile financials, assess risks, and generate an institutional-grade investment recommendation.
      </p>

      <form onSubmit={handleSubmit} className="relative mb-6">
        <div className="relative flex items-center">
          <Search className="absolute left-4 w-5 h-5 text-slate-400" />
          <input
            type="text"
            placeholder="e.g., Apple Inc., NVIDIA, Super Micro Computer..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            disabled={isLoading}
            className="w-full pl-12 pr-32 py-4 rounded-xl bg-slate-950/60 border border-slate-800 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 transition-all text-base disabled:opacity-50"
          />
          <button
            type="submit"
            disabled={!query.trim() || isLoading}
            className="absolute right-2 px-5 py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-medium text-sm transition-all shadow-lg shadow-indigo-600/20 active:scale-95 disabled:opacity-50 disabled:scale-100 disabled:shadow-none flex items-center gap-1.5"
          >
            {isLoading ? 'Researching...' : 'Analyze'}
          </button>
        </div>
      </form>

      <div>
        <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider block mb-2.5">
          Popular Sandbox Queries
        </span>
        <div className="flex flex-wrap gap-2">
          {POPULAR_COMPANIES.map((company) => (
            <button
              key={company}
              type="button"
              onClick={() => handleQuickSelect(company)}
              disabled={isLoading}
              className="px-3.5 py-1.5 rounded-lg text-xs font-medium bg-slate-900 border border-slate-800 text-slate-300 hover:border-slate-700 hover:bg-slate-850 hover:text-white transition-all disabled:opacity-50 cursor-pointer"
            >
              {company}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Loader2, Globe, ShieldAlert, AlertTriangle, Compass, CheckCircle2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface Step {
  id: number;
  label: string;
  subLabel: string;
  icon: any;
}

const RESEARCH_STEPS: Step[] = [
  { id: 0, label: 'Initializing Research Agent', subLabel: 'Configuring Gemini LLM and research parameters...', icon: Compass },
  { id: 1, label: 'Crawling Web for Live Market Intelligence', subLabel: 'Triggering Tavily search crawler across financial journals and news portals...', icon: Globe },
  { id: 2, label: 'Analyzing Financial Indicators & Cash Flows', subLabel: 'Parsing balance sheets, cash flows, and operating margins...', icon: AlertTriangle },
  { id: 3, label: 'Running SWOT & Risk Assessment', subLabel: 'Synthesizing strengths, weaknesses, threats, and competitor landscapes...', icon: ShieldAlert },
  { id: 4, label: 'Finalizing Investment Recommendation', subLabel: 'Compiling thesis score and formatting structured report...', icon: CheckCircle2 }
];

export const LoadingState: React.FC = () => {
  const [activeStep, setActiveStep] = useState(0);

  useEffect(() => {
    const intervals = [2500, 3500, 3000, 2500];
    let currentStep = 0;

    const runNext = () => {
      if (currentStep < RESEARCH_STEPS.length - 1) {
        currentStep += 1;
        setActiveStep(currentStep);
        setTimeout(runNext, intervals[currentStep - 1] || 2000);
      }
    };

    const timer = setTimeout(runNext, intervals[0]);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="glass-panel p-8 rounded-2xl border border-white/5 shadow-xl flex flex-col items-center justify-center min-h-[400px]">
      <div className="relative flex items-center justify-center mb-8">
        <div className="absolute w-24 h-24 rounded-full border border-indigo-500/30 animate-ping opacity-25"></div>
        <div className="absolute w-16 h-16 rounded-full border-2 border-indigo-500/50 animate-pulse opacity-40"></div>
        <div className="p-5 bg-indigo-600/10 border border-indigo-500/25 rounded-2xl shadow-lg relative">
          <Loader2 className="w-8 h-8 text-indigo-400 animate-spin" />
        </div>
      </div>

      <h3 className="text-lg font-semibold text-slate-100 mb-2">Analyzing Company Data</h3>
      <p className="text-sm text-slate-400 text-center max-w-md mb-8">
        Please wait. Our agent is reading real-time information and conducting cross-comparison. This may take up to 10-15 seconds.
      </p>

      <div className="w-full max-w-md space-y-4">
        {RESEARCH_STEPS.map((step) => {
          const isActive = step.id === activeStep;
          const isCompleted = step.id < activeStep;
          const Icon = step.icon;

          return (
            <div
              key={step.id}
              className={`flex items-start gap-4.5 p-3.5 rounded-xl border transition-all ${
                isActive
                  ? 'bg-indigo-950/20 border-indigo-500/30 shadow-md shadow-indigo-950/10'
                  : isCompleted
                  ? 'bg-slate-900/10 border-emerald-500/10 opacity-70'
                  : 'bg-transparent border-transparent opacity-30'
              }`}
            >
              <div
                className={`p-2 rounded-lg border transition-all ${
                  isActive
                    ? 'bg-indigo-500/20 border-indigo-500/35 text-indigo-400'
                    : isCompleted
                    ? 'bg-emerald-500/25 border-emerald-500/40 text-emerald-400'
                    : 'bg-slate-900 border-slate-800 text-slate-500'
                }`}
              >
                <Icon className="w-4 h-4" />
              </div>

              <div className="flex-1 text-left">
                <h4
                  className={`text-sm font-semibold transition-all ${
                    isActive
                      ? 'text-indigo-300'
                      : isCompleted
                      ? 'text-emerald-400/90'
                      : 'text-slate-400'
                  }`}
                >
                  {step.label}
                </h4>
                <p className="text-xs text-slate-400/80 mt-0.5">{step.subLabel}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ResearchReport } from '../types';
import { 
  TrendingUp, TrendingDown, AlertTriangle, ShieldCheck, 
  HelpCircle, Compass, ListTodo, Users, FileText, ExternalLink 
} from 'lucide-react';

interface ResearchResultsProps {
  report: ResearchReport;
}

export const ResearchResults: React.FC<ResearchResultsProps> = ({ report }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'financials' | 'competitors' | 'risks' | 'sources'>('overview');

  const { 
    companyName, recommendation, score, summary, 
    financialHealth, growthDrivers, risks, swot, competitors, sources 
  } = report;

  // Verdict style helpers
  const getVerdictStyle = () => {
    switch (recommendation) {
      case 'Invest':
        return {
          bg: 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400',
          gaugeColor: 'stroke-emerald-400',
          icon: ShieldCheck,
          label: 'Strong Invest Recommendation'
        };
      case 'Consider':
        return {
          bg: 'bg-amber-500/10 border-amber-500/30 text-amber-400',
          gaugeColor: 'stroke-amber-400',
          icon: HelpCircle,
          label: 'Caution / Opportunity'
        };
      case 'Pass':
        return {
          bg: 'bg-rose-500/10 border-rose-500/30 text-rose-400',
          gaugeColor: 'stroke-rose-400',
          icon: AlertTriangle,
          label: 'Avoid / High Risk'
        };
      default:
        return {
          bg: 'bg-slate-500/10 border-slate-500/30 text-slate-400',
          gaugeColor: 'stroke-slate-400',
          icon: HelpCircle,
          label: 'Undecided'
        };
    }
  };

  const verdict = getVerdictStyle();
  const VerdictIcon = verdict.icon;

  // Calculate SVGs for Gauge
  const radius = 40;
  const stroke = 8;
  const normalizedRadius = radius - stroke * 2;
  const circumference = normalizedRadius * 2 * Math.PI;
  const strokeDashoffset = circumference - (score / 100) * circumference;

  return (
    <div className="space-y-6">
      {/* Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Recommendation Score Gauge */}
        <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl flex flex-col items-center justify-center text-center">
          <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4">
            InvestIQ Score
          </span>
          <div className="relative flex items-center justify-center w-28 h-28 mb-4">
            <svg className="w-full h-full transform -rotate-90">
              <circle
                className="stroke-slate-800"
                fill="transparent"
                strokeWidth={stroke}
                r={normalizedRadius}
                cx={radius + stroke}
                cy={radius + stroke}
              />
              <circle
                className={`transition-all duration-1000 ${verdict.gaugeColor}`}
                fill="transparent"
                strokeWidth={stroke}
                strokeDasharray={`${circumference} ${circumference}`}
                style={{ strokeDashoffset }}
                strokeLinecap="round"
                r={normalizedRadius}
                cx={radius + stroke}
                cy={radius + stroke}
              />
            </svg>
            <div className="absolute text-center">
              <span className="text-3xl font-extrabold text-white">{score}</span>
              <span className="text-[10px] text-slate-500 block -mt-1">/ 100</span>
            </div>
          </div>
          <span className="text-xs text-slate-400 mt-2">Overall conviction score</span>
        </div>

        {/* Verdict Box */}
        <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl md:col-span-2 flex flex-col justify-between">
          <div>
            <div className="flex items-center justify-between mb-4">
              <div>
                <h3 className="text-xl font-bold text-white mb-0.5">{companyName}</h3>
                <p className="text-xs text-slate-400">Agent Recommendation</p>
              </div>
              <div className={`px-4 py-2 rounded-xl border flex items-center gap-2 font-bold text-sm uppercase tracking-wider ${verdict.bg}`}>
                <VerdictIcon className="w-4 h-4" />
                <span>{recommendation}</span>
              </div>
            </div>
            <p className="text-sm text-slate-300 leading-relaxed font-medium">
              {summary}
            </p>
          </div>

          <div className="mt-4 pt-4 border-t border-white/5 flex items-center justify-between text-xs text-slate-500">
            <span>Model: Gemini 2.5 Flash</span>
            {report.createdAt && (
              <span>Analyzed on {new Date(report.createdAt).toLocaleDateString()}</span>
            )}
          </div>
        </div>
      </div>

      {/* Tabs Menu */}
      <div className="glass-panel p-1 rounded-xl border border-white/5 flex overflow-x-auto gap-1">
        {(['overview', 'financials', 'competitors', 'risks', 'sources'] as const).map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-[100px] py-2 px-3 rounded-lg text-xs font-semibold uppercase tracking-wider transition-all cursor-pointer ${
              activeTab === tab 
                ? 'bg-indigo-600 text-white shadow-md shadow-indigo-600/10' 
                : 'text-slate-400 hover:text-slate-200 hover:bg-white/5'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* Tabs Content */}
      <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl min-h-[300px]">
        {/* OVERVIEW & SWOT */}
        {activeTab === 'overview' && (
          <div className="space-y-6">
            <h3 className="text-base font-bold text-slate-100 flex items-center gap-2 mb-4">
              <Compass className="w-5 h-5 text-indigo-400" />
              SWOT Quadrant Analysis
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Strengths */}
              <div className="p-4.5 rounded-xl bg-emerald-500/5 border border-emerald-500/10">
                <span className="text-xs font-bold text-emerald-400 uppercase tracking-wider block mb-3">
                  Strengths
                </span>
                <ul className="space-y-2 text-sm text-slate-300">
                  {swot.strengths.map((s, idx) => (
                    <li key={idx} className="flex items-start gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 mt-1.5 flex-shrink-0" />
                      <span>{s}</span>
                    </li>
                  ))}
                </ul>
              </div>

              {/* Weaknesses */}
              <div className="p-4.5 rounded-xl bg-amber-500/5 border border-amber-500/10">
                <span className="text-xs font-bold text-amber-400 uppercase tracking-wider block mb-3">
                  Weaknesses
                </span>
                <ul className="space-y-2 text-sm text-slate-300">
                  {swot.weaknesses.map((w, idx) => (
                    <li key={idx} className="flex items-start gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-amber-400 mt-1.5 flex-shrink-0" />
                      <span>{w}</span>
                    </li>
                  ))}
                </ul>
              </div>

              {/* Opportunities */}
              <div className="p-4.5 rounded-xl bg-indigo-500/5 border border-indigo-500/10">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-wider block mb-3">
                  Opportunities
                </span>
                <ul className="space-y-2 text-sm text-slate-300">
                  {swot.opportunities.map((o, idx) => (
                    <li key={idx} className="flex items-start gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                      <span>{o}</span>
                    </li>
                  ))}
                </ul>
              </div>

              {/* Threats */}
              <div className="p-4.5 rounded-xl bg-rose-500/5 border border-rose-500/10">
                <span className="text-xs font-bold text-rose-400 uppercase tracking-wider block mb-3">
                  Threats
                </span>
                <ul className="space-y-2 text-sm text-slate-300">
                  {swot.threats.map((t, idx) => (
                    <li key={idx} className="flex items-start gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-rose-400 mt-1.5 flex-shrink-0" />
                      <span>{t}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
        )}

        {/* FINANCIALS */}
        {activeTab === 'financials' && (
          <div className="space-y-6">
            <h3 className="text-base font-bold text-slate-100 flex items-center gap-2 mb-4">
              <FileText className="w-5 h-5 text-indigo-400" />
              Financial Health & Growth Drivers
            </h3>

            <div className="p-4.5 rounded-xl bg-slate-950/60 border border-slate-800 mb-6">
              <p className="text-sm text-slate-300 leading-relaxed font-medium">
                {financialHealth}
              </p>
            </div>

            <div>
              <span className="text-xs font-bold text-slate-500 uppercase tracking-wider block mb-3">
                Key Growth Catalyst Drivers
              </span>
              <ul className="space-y-3.5 text-sm text-slate-300">
                {growthDrivers.map((driver, idx) => (
                  <li key={idx} className="flex items-start gap-3">
                    <div className="p-1 rounded-md bg-indigo-500/10 border border-indigo-500/20 mt-0.5 flex-shrink-0">
                      <TrendingUp className="w-3.5 h-3.5 text-indigo-400" />
                    </div>
                    <span>{driver}</span>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        )}

        {/* COMPETITORS */}
        {activeTab === 'competitors' && (
          <div className="space-y-6">
            <h3 className="text-base font-bold text-slate-100 flex items-center gap-2 mb-4">
              <Users className="w-5 h-5 text-indigo-400" />
              Competitive Landscape Overview
            </h3>

            <div className="overflow-x-auto rounded-xl border border-slate-800">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-950/70 border-b border-slate-850">
                    <th className="p-4 text-xs font-bold text-slate-400 uppercase">Competitor Name</th>
                    <th className="p-4 text-xs font-bold text-slate-400 uppercase">Est. Market Cap</th>
                    <th className="p-4 text-xs font-bold text-slate-400 uppercase">Core Strength</th>
                  </tr>
                </thead>
                <tbody>
                  {competitors.map((comp, idx) => (
                    <tr key={idx} className="border-b border-slate-850 bg-slate-900/10 hover:bg-slate-900/30">
                      <td className="p-4 text-sm font-semibold text-white">{comp.name}</td>
                      <td className="p-4 text-sm text-indigo-300 font-mono">{comp.marketCap}</td>
                      <td className="p-4 text-sm text-slate-400 leading-relaxed">{comp.strengths}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* RISKS */}
        {activeTab === 'risks' && (
          <div className="space-y-6">
            <h3 className="text-base font-bold text-slate-100 flex items-center gap-2 mb-4">
              <ListTodo className="w-5 h-5 text-indigo-400" />
              Risk Assessment Profile
            </h3>

            <ul className="space-y-3.5 text-sm text-slate-300">
              {risks.map((risk, idx) => (
                <li key={idx} className="flex items-start gap-3 p-3.5 rounded-xl bg-rose-500/5 border border-rose-500/10">
                  <div className="p-1 rounded-md bg-rose-500/10 border border-rose-500/20 mt-0.5 flex-shrink-0">
                    <TrendingDown className="w-3.5 h-3.5 text-rose-400" />
                  </div>
                  <span>{risk}</span>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* SOURCES & CITATIONS */}
        {activeTab === 'sources' && (
          <div className="space-y-6">
            <h3 className="text-base font-bold text-slate-100 flex items-center gap-2 mb-4">
              <FileText className="w-5 h-5 text-indigo-400" />
              Primary Reference Citations
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {sources.map((src, idx) => (
                <a
                  key={idx}
                  href={src.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="p-4 rounded-xl bg-slate-950/60 border border-slate-800 hover:border-indigo-500/50 hover:bg-slate-900/30 transition-all flex items-center justify-between group"
                >
                  <div className="max-w-[85%]">
                    <h4 className="text-sm font-semibold text-white group-hover:text-indigo-400 transition-colors truncate">
                      {src.title}
                    </h4>
                    <p className="text-xs text-slate-500 truncate mt-1">{src.url}</p>
                  </div>
                  <ExternalLink className="w-4 h-4 text-slate-500 group-hover:text-indigo-400 transition-colors" />
                </a>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { ResearchReport } from '../types';
import { History, TrendingUp, HelpCircle, AlertTriangle, ChevronRight } from 'lucide-react';

interface HistorySidebarProps {
  history: ResearchReport[];
  onSelectReport: (report: ResearchReport) => void;
  selectedReportId?: string;
}

export const HistorySidebar: React.FC<HistorySidebarProps> = ({ 
  history, 
  onSelectReport, 
  selectedReportId 
}) => {
  const getBadgeStyle = (rec: string) => {
    switch (rec) {
      case 'Invest':
        return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20';
      case 'Consider':
        return 'bg-amber-500/10 text-amber-400 border-amber-500/20';
      case 'Pass':
        return 'bg-rose-500/10 text-rose-400 border-rose-500/20';
      default:
        return 'bg-slate-500/10 text-slate-400 border-slate-500/20';
    }
  };

  return (
    <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl flex flex-col h-full">
      <h3 className="text-base font-bold text-slate-100 mb-4 flex items-center gap-2">
        <History className="w-5 h-5 text-indigo-400" />
        Analysis History
      </h3>

      {history.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center p-4">
          <p className="text-sm text-slate-500">No past analyses found.</p>
          <p className="text-xs text-slate-600 mt-1">Start by searching a company name above.</p>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto space-y-3 pr-1">
          {history.map((report) => {
            const isSelected = report._id === selectedReportId;
            return (
              <button
                key={report._id}
                onClick={() => onSelectReport(report)}
                className={`w-full text-left p-3.5 rounded-xl border transition-all flex items-center justify-between group cursor-pointer ${
                  isSelected 
                    ? 'bg-indigo-600/10 border-indigo-500/40' 
                    : 'bg-slate-900/40 border-slate-800 hover:border-slate-700 hover:bg-slate-900/60'
                }`}
              >
                <div className="max-w-[80%]">
                  <h4 className="text-sm font-semibold text-white group-hover:text-indigo-400 transition-colors truncate">
                    {report.companyName}
                  </h4>
                  <div className="flex items-center gap-2 mt-2">
                    <span className={`px-2 py-0.5 text-[10px] uppercase font-bold rounded border ${getBadgeStyle(report.recommendation)}`}>
                      {report.recommendation}
                    </span>
                    <span className="text-[10px] text-slate-500 font-mono">Score: {report.score}</span>
                  </div>
                </div>
                <ChevronRight className="w-4 h-4 text-slate-500 group-hover:text-indigo-400 transition-colors" />
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
};

import { useState, useEffect } from 'react';
import { ResearchReport } from './types';
import { DashboardHeader } from './components/DashboardHeader';
import { ResearchForm } from './components/ResearchForm';
import { LoadingState } from './components/LoadingState';
import { ResearchResults } from './components/ResearchResults';
import { HistorySidebar } from './components/HistorySidebar';
import { analyzeCompany, getHistory } from './services/api';
import { Sparkles, Brain, Info } from 'lucide-react';

function App() {
  const [history, setHistory] = useState<ResearchReport[]>([]);
  const [selectedReport, setSelectedReport] = useState<ResearchReport | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Check if API is running in simulated sandbox mode (offline/no keys)
  const [isSandboxMode, setIsSandboxMode] = useState(false);

  useEffect(() => {
    loadHistory();
  }, []);

  const loadHistory = async () => {
    try {
      const data = await getHistory();
      setHistory(data);
      if (data.length > 0 && !selectedReport) {
        setSelectedReport(data[0]);
      }

      // If there are offline mock markers, notify sandbox status
      const hasOfflineReport = data.some(item => item.offline);
      if (hasOfflineReport) {
        setIsSandboxMode(true);
      }
    } catch (err) {
      console.warn('Failed to load analysis history:', err);
    }
  };

  const handleResearch = async (companyName: string) => {
    setIsLoading(true);
    setError(null);
    setSelectedReport(null);

    try {
      const report = await analyzeCompany(companyName);
      setSelectedReport(report);
      if (report.offline) {
        setIsSandboxMode(true);
      }
      // Reload history to include the new report
      await loadHistory();
    } catch (err: any) {
      console.error(err);
      setError(
        err.response?.data?.error || 
        'An error occurred while compiling research. Ensure backend server is running.'
      );
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen">
      <DashboardHeader isOffline={isSandboxMode} />

      <main className="flex-1 p-6 max-w-7xl mx-auto w-full grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Left Column: Form & General Info */}
        <div className="lg:col-span-4 space-y-6">
          <ResearchForm onSearch={handleResearch} isLoading={isLoading} />

          {/* Agent Information Box */}
          <div className="glass-panel p-5 rounded-2xl border border-white/5 bg-indigo-950/5">
            <h4 className="text-sm font-bold text-slate-100 flex items-center gap-2 mb-2">
              <Brain className="w-4.5 h-4.5 text-indigo-400" />
              How the Agent Works
            </h4>
            <ul className="text-xs text-slate-400 space-y-2">
              <li className="flex items-start gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                <span>Crawls live search data for active stock indicators & market trends.</span>
              </li>
              <li className="flex items-start gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                <span>Aggregates competitor metrics, valuations, and SWOT profiles.</span>
              </li>
              <li className="flex items-start gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                <span>Evaluates growth drivers and parses risks using Google Gemini reasoning.</span>
              </li>
            </ul>
          </div>

          {/* History Sidebar - Visible under Search on smaller screens */}
          <div className="block lg:hidden">
            <HistorySidebar
              history={history}
              onSelectReport={setSelectedReport}
              selectedReportId={selectedReport?._id}
            />
          </div>
        </div>

        {/* Right Column: Output / Loaders / Results */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          {isLoading && <LoadingState />}

          {error && (
            <div className="glass-panel p-6 rounded-2xl border border-rose-500/20 bg-rose-500/5 text-slate-100 flex items-start gap-3.5">
              <Info className="w-6 h-6 text-rose-400 flex-shrink-0 mt-0.5" />
              <div>
                <h4 className="font-bold text-rose-400">Research Compilation Failed</h4>
                <p className="text-sm text-slate-350 mt-1">{error}</p>
              </div>
            </div>
          )}

          {!isLoading && !error && selectedReport && (
            <ResearchResults report={selectedReport} />
          )}

          {!isLoading && !error && !selectedReport && (
            <div className="glass-panel p-8 rounded-2xl border border-white/5 shadow-xl flex flex-col items-center justify-center min-h-[400px] text-center">
              <div className="p-4 bg-slate-900 border border-slate-800 rounded-full mb-4">
                <Sparkles className="w-8 h-8 text-indigo-400" />
              </div>
              <h3 className="text-base font-bold text-white mb-2">No Active Analysis</h3>
              <p className="text-sm text-slate-400 max-w-sm">
                Enter a company name on the left to start your first research session, or select a report from the history list.
              </p>
            </div>
          )}
        </div>

        {/* Desktop History Sidebar (Fixed in layout) */}
        <div className="hidden lg:block lg:col-span-12 mt-6">
          <HistorySidebar
            history={history}
            onSelectReport={setSelectedReport}
            selectedReportId={selectedReport?._id}
          />
        </div>
      </main>
    </div>
  );
}

export default App;

