{
  "name": "investiq-ai-root",
  "version": "1.0.0",
  "private": true,
  "scripts": {
    "install:all": "npm install --prefix client && npm install --prefix server --legacy-peer-deps",
    "dev:server": "npm run dev --prefix server",
    "dev:client": "npm run dev --prefix client",
    "dev": "npx concurrently -k -p \"[{name}]\" -n \"server,client\" -c \"yellow,blue\" \"npm run dev:server\" \"npm run dev:client\""
  }
}

export interface Competitor {
  name: string;
  marketCap: string;
  strengths: string;
}

export interface NewsItem {
  title: string;
  source: string;
  snippet: string;
  url: string;
}

export interface ResearchReport {
  _id?: string;
  companyName: string;
  recommendation: 'Invest' | 'Consider' | 'Pass';
  investmentScore: number;
  confidenceScore: number;
  companyOverview: string;
  businessModel: string;
  industry: string;
  financialHealth: string;
  strengths: string[];
  weaknesses: string[];
  competitors: Competitor[];
  recentNews: NewsItem[];
  riskAnalysis: string;
  growthPotential: string;
  reasoning: string;
  createdAt?: string;
  offline?: boolean;
}

import mongoose from 'mongoose';

const CompetitorSchema = new mongoose.Schema({
  name: { type: String, required: true },
  marketCap: { type: String, required: true },
  strengths: { type: String, required: true }
});

const NewsItemSchema = new mongoose.Schema({
  title: { type: String, required: true },
  source: { type: String, required: true },
  snippet: { type: String, required: true },
  url: { type: String, required: true }
});

const ReportSchema = new mongoose.Schema({
  companyName: { type: String, required: true },
  recommendation: { 
    type: String, 
    enum: ['Invest', 'Consider', 'Pass'], 
    required: true 
  },
  investmentScore: { type: Number, required: true },
  confidenceScore: { type: Number, required: true },
  companyOverview: { type: String, required: true },
  businessModel: { type: String, required: true },
  industry: { type: String, required: true },
  financialHealth: { type: String, required: true },
  strengths: [{ type: String }],
  weaknesses: [{ type: String }],
  competitors: [CompetitorSchema],
  recentNews: [NewsItemSchema],
  riskAnalysis: { type: String, required: true },
  growthPotential: { type: String, required: true },
  reasoning: { type: String, required: true },
  createdAt: { type: Date, default: Date.now }
});

const Report = mongoose.model('Report', ReportSchema);
export default Report;

// High fidelity mock service for investment analysis containing all SaaS layout cards
export const generateMockReport = (companyName) => {
  const normalized = companyName.toLowerCase().trim();

  if (normalized.includes('apple') || normalized.includes('aapl')) {
    return {
      companyName: 'Apple Inc. (AAPL)',
      recommendation: 'Invest',
      investmentScore: 89,
      confidenceScore: 92,
      companyOverview: 'Apple Inc. designs, manufactures, and markets smartphones, personal computers, tablets, wearables, and accessories worldwide. The company is transitioning from a hardware-centric device manufacturer into a digital consumer ecosystem powerhouse, leveraging its active install base of over 2.2 billion devices.',
      businessModel: 'Ecosystem lock-in. Apple designs proprietary hardware (iPhone, Mac, iPad, Watch) powered by proprietary silicon and operating systems, creating a high-switching-cost environment. It monetizes this user base through high-margin digital services (App Store, Apple Pay, iCloud, Music, Arcade, and subscriptions).',
      industry: 'Consumer Technology & Services. The market is shifting from sheer hardware shipment volume growth to ecosystem monetization, artificial intelligence integration (on-device LLMs), and spatial computing/augmented reality.',
      financialHealth: 'Outstanding. Generates ~$100B in annual Free Cash Flow. Boasts a massive capital return program ($110B in share repurchases in FY24 alone). Operating margin remains robust at ~30%, with Services gross margin exceeding 74%. Debt is well-managed with a AAA-equivalent leverage profile.',
      strengths: [
        'Unmatched consumer brand loyalty and pricing power (gross margins consistently above 45%).',
        'Proprietary Apple Silicon (A-series, M-series) providing superior performance and cost efficiency.',
        'High margin recurring services revenue stream stabilizing quarterly earnings volatility.'
      ],
      weaknesses: [
        'Heavy dependence on the iPhone segment, which still represents ~50% of total revenue.',
        'Geopolitical exposure in manufacturing supply chain, particularly with Taiwan and China.',
        'Regulatory headwinds concerning App Store fees and search monetization agreements.'
      ],
      competitors: [
        { name: 'Samsung Electronics', marketCap: '$380B', strengths: 'Vertical integration in semiconductor memory and diverse consumer product portfolio.' },
        { name: 'Microsoft Corporation', marketCap: '$3.2T', strengths: 'Dominance in corporate desktop operating systems, cloud productivity, and enterprise AI.' },
        { name: 'Alphabet Inc. (Google)', marketCap: '$2.1T', strengths: 'Android OS dominance, search marketing monopoly, and deep generative AI infrastructure.' }
      ],
      recentNews: [
        { title: 'Apple launches Apple Intelligence, bringing generative AI to iOS 18', source: 'TechCrunch', snippet: 'Apple announced its new on-device AI system, positioning privacy as the core differentiator against cloud-based AI providers.', url: 'https://techcrunch.com' },
