import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { HumanMessage, SystemMessage } from '@langchain/core/messages';
import axios from 'axios';
import { generateMockReport } from './mockService.js';

// ─────────────────────────────────────────────
// STEP 2: TAVILY MULTI-TOPIC INTELLIGENCE GATHER
// ─────────────────────────────────────────────

/**
 * Run a single Tavily search query.
 * @param {string} query
 * @param {string} tavilyKey
 * @returns {Promise<Array<{title, url, content}>>}
 */
async function tavilySearch(query, tavilyKey) {
  try {
    const res = await axios.post(
      'https://api.tavily.com/search',
      {
        api_key: tavilyKey,
        query,
        search_depth: 'advanced',
        max_results: 4,
        include_answer: false,
      },
      { timeout: 12000 }
    );
    return res.data.results || [];
  } catch (err) {
    console.warn(`[Tavily] Query failed: "${query}" — ${err.message}`);
    return [];
  }
}

/**
 * STEP 2: Execute targeted searches across 12 intelligence categories.
 * @param {string} companyName
 * @param {string} tavilyKey
 * @returns {Promise<object>} rawIntelligence map
 */
async function gatherIntelligence(companyName, tavilyKey) {
  console.log(`[Agent Step 2] Launching parallel Tavily search queries for: ${companyName}`);

  const queries = {
    companyOverview:    `${companyName} company overview business segments operations 2025`,
    industry:           `${companyName} industry sector market size trends outlook 2025 2026`,
    businessModel:      `${companyName} business model revenue streams monetization strategy`,
    revenue:            `${companyName} revenue earnings annual growth rate quarterly results 2024 2025`,
    profitability:      `${companyName} net profit margin EBITDA operating income profitability 2025`,
    debt:               `${companyName} debt balance sheet liabilities debt-to-equity leverage ratio`,
    cashFlow:           `${companyName} free cash flow operating cash flow capital expenditure 2024 2025`,
    competitors:        `${companyName} main competitors market share comparison competitive landscape`,
    marketPosition:     `${companyName} market position brand valuation market capitalization ranking`,
    recentNews:         `${companyName} latest news 2025 recent developments announcements`,
    growthDrivers:      `${companyName} growth drivers catalysts expansion pipeline opportunities`,
    risks:              `${companyName} risks challenges regulatory headwinds threats 2025`,
  };

  // Fire all searches in parallel for speed
  const entries = Object.entries(queries);
  const results = await Promise.all(
    entries.map(([key, q]) =>
      tavilySearch(q, tavilyKey).then(hits => [key, hits])
    )
  );

  const intelligence = {};
  for (const [key, hits] of results) {
    intelligence[key] = hits
      .map(h => `• [${h.title}] (${h.url})\n  ${h.content?.slice(0, 500) || ''}`)
      .join('\n\n') || 'No live data retrieved for this category.';
  }

  // Collect all raw source URLs for citation
  const allSources = results.flatMap(([, hits]) =>
    hits.map(h => ({ title: h.title, url: h.url, source: new URL(h.url).hostname.replace('www.', '') }))
  ).filter((v, i, arr) => arr.findIndex(x => x.url === v.url) === i);  // deduplicate

  intelligence._sources = allSources;

  console.log(`[Agent Step 2] Intelligence gathered across ${entries.length} categories. Total sources: ${allSources.length}`);
  return intelligence;
}

// ─────────────────────────────────────────────
// STEP 3: GEMINI ANALYST EVALUATION
// ─────────────────────────────────────────────

const SYSTEM_PROMPT = `You are Dr. Maya Krishnan, a Senior Managing Director at a global equity research firm with 20+ years covering Asian and US equity markets.

Your methodology:
- You do NOT summarize. You ANALYZE and EVALUATE.
- You form independent assessments based on evidence.
- You apply first-principles thinking to each financial metric.
- You use the evidence to derive a score on each dimension, then synthesize a final investment score.
- You are direct, data-driven, and do not hedge without reason.

Scoring framework:
- revenueGrowthScore (0–100): Based on historical CAGR, acceleration/deceleration, and quality of growth.
- financialStabilityScore (0–100): Based on debt levels, interest coverage, cash runway, FCF generation.
- competitiveAdvantageScore (0–100): Based on moats — brand, switching costs, network effects, IP, scale.
- industryOutlookScore (0–100): Based on TAM trajectory, tailwinds/headwinds, regulatory environment.
- innovationScore (0–100): Based on R&D spend, patent activity, product pipeline, disruption potential.
- newsSentimentScore (0–100): Based on quality and direction of recent news — management changes, lawsuits, partnerships, product launches.
- riskFactorScore (0–100): INVERSE risk score. 100 = very low risk. 0 = existential risk.
- growthPotentialScore (0–100): Based on runway, addressable market, execution track record.

Final investmentScore = weighted average:
  revenueGrowthScore × 0.15
  financialStabilityScore × 0.20
  competitiveAdvantageScore × 0.20
  industryOutlookScore × 0.10
  innovationScore × 0.10
  newsSentimentScore × 0.05
  riskFactorScore × 0.10
  growthPotentialScore × 0.10

Decision rules (apply STRICTLY):
  investmentScore ≥ 80 → recommendation = "Invest"
  investmentScore 60–79 → recommendation = "Consider"
  investmentScore < 60 → recommendation = "Pass"

You MUST explain every dimension score with 2-3 sentences of analysis.
Return ONLY raw valid JSON. No markdown. No preamble.`;

/**
 * Build the user message fed to Gemini with all gathered intelligence.
 */
function buildAnalystPrompt(companyName, intel) {
  return `Conduct a full equity research evaluation for: ${companyName}

Using the intelligence gathered below, evaluate each dimension and produce the final structured JSON output.

=== INTELLIGENCE GATHERED ===

[COMPANY OVERVIEW]
${intel.companyOverview}

[INDUSTRY & SECTOR]
${intel.industry}

[BUSINESS MODEL]
${intel.businessModel}

[REVENUE & GROWTH]
${intel.revenue}

[PROFITABILITY]
${intel.profitability}

[DEBT & BALANCE SHEET]
${intel.debt}

[CASH FLOW]
${intel.cashFlow}

[COMPETITORS & MARKET SHARE]
${intel.competitors}

[MARKET POSITION & BRAND]
${intel.marketPosition}

[RECENT NEWS & SENTIMENT]
${intel.recentNews}

[GROWTH DRIVERS & CATALYSTS]
${intel.growthDrivers}

[RISKS & HEADWINDS]
${intel.risks}

=== REQUIRED JSON OUTPUT ===

Return ONLY this exact JSON structure — no extra fields, no markdown fences:

{
