/**
 * Three-step AI Investment Research Agent:
 *   Step 1 → Validate and normalize company name
 *   Step 2 → Gather multi-category intelligence via Tavily
 *   Step 3 → Send to Gemini analyst for evaluation + structured JSON output
 *
 * @param {string} companyName
 * @returns {Promise<object>} Structured research report
 */
export const performResearch = async (companyName) => {
  const geminiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_GENAI_API_KEY;
  const tavilyKey = process.env.TAVILY_API_KEY;

  // ── STEP 1: Receive & validate ──
  console.log(`\n${'═'.repeat(60)}`);
  console.log(`[Agent Step 1] Received research request: "${companyName}"`);
  console.log(`${'═'.repeat(60)}`);

  if (!geminiKey) {
    console.warn('[Agent Step 1] GEMINI_API_KEY missing — switching to sandbox mock data.');
    return generateMockReport(companyName);
  }

  let intelligence = {};

  // ── STEP 2: Gather live intelligence ──
  if (tavilyKey) {
    intelligence = await gatherIntelligence(companyName, tavilyKey);
  } else {
    console.warn('[Agent Step 2] TAVILY_API_KEY missing — Gemini will rely on training knowledge only.');
    // Provide empty placeholders so the prompt still works
    const categories = ['companyOverview','industry','businessModel','revenue','profitability',
      'debt','cashFlow','competitors','marketPosition','recentNews','growthDrivers','risks'];
    for (const c of categories) {
      intelligence[c] = 'No live search data available. Evaluate using training knowledge.';
    }
    intelligence._sources = [];
  }

  // ── STEP 3: Gemini analyst evaluation ──
  try {
    console.log(`[Agent Step 3] Sending intelligence to Gemini for equity analysis...`);

    const model = new ChatGoogleGenerativeAI({
      apiKey: geminiKey,
      modelName: 'gemini-2.5-flash',
      maxOutputTokens: 4096,
      temperature: 0.15, // Low temperature for consistent analytical output
    });

    const messages = [
      new SystemMessage(SYSTEM_PROMPT),
      new HumanMessage(buildAnalystPrompt(companyName, intelligence)),
    ];

    const response = await model.invoke(messages);

    let raw = typeof response.content === 'string'
      ? response.content
      : JSON.stringify(response.content);

    // Strip markdown fences if model still wraps output
    raw = raw.trim()
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();

    let report;
    try {
      report = JSON.parse(raw);
    } catch (parseErr) {
      console.error('[Agent Step 3] JSON parse failed. Raw Gemini output:\n', raw.slice(0, 500));
      throw new Error('Gemini returned malformed JSON.');
    }

    // ── Enforce decision rule server-side ──
    const score = Number(report.investmentScore) || 0;
    if (score >= 80) {
      report.recommendation = 'Invest';
    } else if (score >= 60) {
      report.recommendation = 'Consider';
    } else {
      report.recommendation = 'Pass';
    }

    // Attach raw sources from Tavily
    if (!report.recentNews || report.recentNews.length === 0) {
      report.recentNews = (intelligence._sources || []).slice(0, 3).map(s => ({
        title: s.title,
        source: s.source,
        snippet: 'Retrieved via live Tavily web search.',
        url: s.url,
      }));
    }

    console.log(`[Agent Step 3] Analysis complete. Score: ${score} → ${report.recommendation}`);
    console.log(`${'═'.repeat(60)}\n`);

    return report;

  } catch (err) {
    console.error('[Agent Step 3] Gemini evaluation failed:', err.message);
    console.warn('[Agent Step 3] Falling back to high-fidelity sandbox mock.');
    return generateMockReport(companyName);
  }
};

