            fill="transparent" strokeWidth={stroke}
            strokeDasharray={`${circ} ${circ}`}
            style={{ strokeDashoffset: offset }}
            strokeLinecap="round"
            r={normRadius} cx={radius} cy={radius}
          />
        </svg>
        <div className="absolute text-center">
