import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { connectDB } from './config/db.js';
import researchRoutes from './routes/researchRoutes.js';

// Load environment variables
dotenv.config();

const app = express();
const PORT = process.env.PORT || 5001;

// Middleware
app.use(cors());
app.use(express.json());

// Database connection
connectDB();

// API Routes
app.use('/api/research', researchRoutes);

// ── Enhanced Health Check endpoint ──────────────────────────
app.get('/health', (req, res) => {
  const geminiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_GENAI_API_KEY;
  const tavilyKey = process.env.TAVILY_API_KEY;
  const mongoUri  = process.env.MONGODB_URI;

  const status = {
    service:  'InvestIQ AI API Server',
    status:   'ok',
    port:     PORT,
    services: {
      gemini: {
        connected: !!(geminiKey && !geminiKey.includes('YOUR_KEY')),
        keyPrefix: geminiKey ? geminiKey.slice(0, 10) + '...' : 'NOT SET',
      },
      tavily: {
        connected: !!(tavilyKey && !tavilyKey.includes('YOUR_KEY')),
        keyPrefix: tavilyKey ? tavilyKey.slice(0, 8) + '...' : 'NOT SET',
      },
      mongodb: {
        connected: !!(mongoUri && !mongoUri.includes('xxxxx')),
        host: mongoUri ? new URL(mongoUri.replace('mongodb+srv://', 'https://')).hostname : 'NOT SET',
      },
    },
    mode: (!geminiKey || geminiKey.includes('YOUR_KEY'))
      ? '⚠️  SANDBOX (mock data)'
      : '✅  LIVE AI (Gemini + Tavily)',
  };

  res.status(200).json(status);
});

// ── Startup Integration Status Log ──────────────────────────
const geminiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_GENAI_API_KEY;
const tavilyKey = process.env.TAVILY_API_KEY;

// Start server
app.listen(PORT, () => {
  console.log('\n' + '═'.repeat(52));
  console.log('  InvestIQ AI — Server Started');
  console.log('═'.repeat(52));
  console.log(`  Port      : ${PORT}`);
  console.log(`  MongoDB   : ${process.env.MONGODB_URI ? '✅  URI loaded' : '❌  Not set'}`);
  console.log(`  Gemini    : ${geminiKey && !geminiKey.includes('YOUR_KEY') ? '✅  API key loaded → ' + geminiKey.slice(0, 10) + '...' : '❌  Not set (using mock)'}`);
  console.log(`  Tavily    : ${tavilyKey && !tavilyKey.includes('YOUR_KEY') ? '✅  API key loaded → ' + tavilyKey.slice(0, 8) + '...' : '❌  Not set (no live search)'}`);
  console.log(`  Mode      : ${geminiKey && !geminiKey.includes('YOUR_KEY') ? '🚀  LIVE AI MODE' : '🧪  SANDBOX MODE (mock data)'}`);
  console.log('═'.repeat(52) + '\n');
});

/**
 * utils/logger.js
 * Lightweight structured logger with timestamps and severity levels.
 */

const LEVELS = { ERROR: 'ERROR', WARN: 'WARN', INFO: 'INFO', STEP: 'STEP' };

const color = {
  ERROR: '\x1b[31m',   // red
  WARN:  '\x1b[33m',   // yellow
  INFO:  '\x1b[36m',   // cyan
  STEP:  '\x1b[35m',   // magenta
  RESET: '\x1b[0m',
};

function log(level, message) {
  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
  const c = color[level] || '';
  console.log(`${c}[${ts}] [${level}] ${message}${color.RESET}`);
}

export const logger = {
  error: (msg) => log(LEVELS.ERROR, msg),
  warn:  (msg) => log(LEVELS.WARN,  msg),
  info:  (msg) => log(LEVELS.INFO,  msg),
  step:  (msg) => log(LEVELS.STEP,  msg),
};

/**
 * utils/apiResponse.js
 * Standardized JSON response helpers for all Express routes.
 */

export const sendSuccess = (res, data, statusCode = 200) => {
  res.status(statusCode).json({
    success: true,
    data,
  });
};

export const sendError = (res, message, statusCode = 500, details = null) => {
  const payload = { success: false, error: message };
  if (details) payload.details = details;
  res.status(statusCode).json(payload);
};

/**
 * middleware/validate.js
 * Request validation middleware for all API routes.
 */

import { sendError } from '../utils/apiResponse.js';

/**
 * Validates that req.body.companyName is a non-empty string ≤ 100 chars
 * and contains only letters, numbers, spaces, dots, dashes, and parens.
 */
export const validateCompanyName = (req, res, next) => {
  const { companyName } = req.body;

  if (!companyName) {
    return sendError(res, 'companyName is required in the request body.', 400);
  }

  if (typeof companyName !== 'string') {
    return sendError(res, 'companyName must be a string.', 400);
  }

  const trimmed = companyName.trim();

  if (trimmed.length === 0) {
    return sendError(res, 'companyName cannot be empty.', 400);
  }

  if (trimmed.length > 100) {
    return sendError(res, 'companyName must not exceed 100 characters.', 400);
  }

  // Allow letters, numbers, spaces, dots, dashes, parentheses, ampersands
  const allowedPattern = /^[a-zA-Z0-9\s.\-()&,]+$/;
  if (!allowedPattern.test(trimmed)) {
    return sendError(res, 'companyName contains invalid characters.', 400);
  }

  // Attach sanitized value back for downstream use
  req.body.companyName = trimmed;
  next();
};

/**
 * Validates that req.params.id is a valid MongoDB ObjectId format (24 hex chars).
 */
export const validateObjectId = (req, res, next) => {
  const { id } = req.params;
  const objectIdPattern = /^[a-fA-F0-9]{24}$/;

  if (!id || !objectIdPattern.test(id)) {
    return sendError(res, 'Invalid report ID format.', 400);
  }

  next();
};

/**
 * middleware/errorHandler.js
 * Global Express error handling middleware.
 * Must be registered LAST in app.js (after all routes).
 */

import { logger } from '../utils/logger.js';

export const errorHandler = (err, req, res, _next) => {
  logger.error(`Unhandled error on ${req.method} ${req.path}: ${err.message}`);

  // Mongoose validation error
  if (err.name === 'ValidationError') {
    return res.status(400).json({
      success: false,
      error: 'Validation failed',
      details: Object.values(err.errors).map(e => e.message),
    });
  }

  // Mongoose CastError (bad ObjectId)
  if (err.name === 'CastError') {
    return res.status(400).json({ success: false, error: 'Invalid ID format.' });
  }

  // Default 500
  res.status(err.statusCode || 500).json({
    success: false,
    error: err.message || 'Internal Server Error',
  });
};

/**
 * controllers/analysisController.js
 * MVC Controller — handles all /api/analyze and /api/history routes.
 *
 * Workflow for POST /api/analyze:
 *   1. Validate company name (done by middleware before reaching here)
 *   2. Check MongoDB for a recent cached report (< CACHE_TTL_HOURS old)
 *   3. If fresh cache found → return immediately (no LLM call)
 *   4. Otherwise → call langchainService → save to DB → return result
 */

import Report from '../models/Report.js';
import { performResearch } from '../services/langchainService.js';
import { sendSuccess, sendError } from '../utils/apiResponse.js';
import { logger } from '../utils/logger.js';

// Reports younger than this are returned from cache without a new AI call
const CACHE_TTL_HOURS = 24;

// ─────────────────────────────────────────────
// POST /api/analyze
// ─────────────────────────────────────────────
export const analyzeCompany = async (req, res, next) => {
  const { companyName } = req.body;

  try {
    // ── Step 1: Check MongoDB for a recent cached report ──
    const cacheThreshold = new Date(Date.now() - CACHE_TTL_HOURS * 60 * 60 * 1000);

    const cachedReport = await Report.findOne({
      companyName: { $regex: new RegExp(`^${companyName}$`, 'i') },
      createdAt:   { $gte: cacheThreshold },
    }).sort({ createdAt: -1 });

    if (cachedReport) {
      logger.info(`[Cache HIT] Returning cached report for "${companyName}" (ID: ${cachedReport._id})`);
      return sendSuccess(res, { ...cachedReport.toObject(), cached: true });
    }

    logger.info(`[Cache MISS] No fresh report found for "${companyName}". Running AI pipeline...`);

    // ── Step 2: Run the full LangChain → Gemini → analysis pipeline ──
    const reportData = await performResearch(companyName);

    // ── Step 3: Persist to MongoDB ──
    let savedReport;
    try {
      const report = new Report(reportData);
      savedReport = await report.save();
      logger.info(`[DB] Report saved successfully. ID: ${savedReport._id}`);
    } catch (dbErr) {
      logger.warn(`[DB] Could not save report (offline mode): ${dbErr.message}`);
      savedReport = { ...reportData, _id: `offline_${Date.now()}`, offline: true };
    }

    return sendSuccess(res, savedReport, 201);

  } catch (err) {
    logger.error(`[analyzeCompany] ${err.message}`);
    next(err);
  }
};

// ─────────────────────────────────────────────
// GET /api/history
// ─────────────────────────────────────────────
export const getHistory = async (req, res, next) => {
  try {
    const { limit = 20, page = 1 } = req.query;
    const skip = (Number(page) - 1) * Number(limit);

    const [reports, total] = await Promise.all([
      Report.find()
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(Number(limit))
        .select('companyName recommendation investmentScore confidenceScore createdAt'),
      Report.countDocuments(),
    ]);

    return sendSuccess(res, {
      reports,
      pagination: {
        total,
        page:       Number(page),
        limit:      Number(limit),
        totalPages: Math.ceil(total / Number(limit)),
      },
    });
  } catch (err) {
    logger.error(`[getHistory] ${err.message}`);
    // Return empty list gracefully if DB is unavailable
    return sendSuccess(res, { reports: [], pagination: { total: 0, page: 1, limit: 20, totalPages: 0 } });
  }
};

// ─────────────────────────────────────────────
// GET /api/history/:id
// ─────────────────────────────────────────────
export const getReportById = async (req, res, next) => {
  try {
    const report = await Report.findById(req.params.id);

    if (!report) {
      return sendError(res, `Report with ID "${req.params.id}" not found.`, 404);
    }

    return sendSuccess(res, report);
  } catch (err) {
    logger.error(`[getReportById] ${err.message}`);
    next(err);
  }
};

// ─────────────────────────────────────────────
// DELETE /api/history/:id
// ─────────────────────────────────────────────
export const deleteReport = async (req, res, next) => {
  try {
    const report = await Report.findByIdAndDelete(req.params.id);

    if (!report) {
      return sendError(res, `Report with ID "${req.params.id}" not found.`, 404);
    }

    logger.info(`[DB] Report deleted. ID: ${req.params.id}`);
    return sendSuccess(res, { message: `Report for "${report.companyName}" deleted successfully.` });
  } catch (err) {
    logger.error(`[deleteReport] ${err.message}`);
    next(err);
  }
};

/**
 * routes/analysisRoutes.js
 * REST API routes for InvestIQ AI analysis endpoints.
 *
 * POST   /api/analyze          → Run AI investment analysis
 * GET    /api/history          → Paginated history list
 * GET    /api/history/:id      → Single report by ID
 * DELETE /api/history/:id      → Delete a report
 */

import express from 'express';
import {
  analyzeCompany,
  getHistory,
  getReportById,
  deleteReport,
} from '../controllers/analysisController.js';
import { validateCompanyName, validateObjectId } from '../middleware/validate.js';

const router = express.Router();

// POST /api/analyze
router.post('/analyze', validateCompanyName, analyzeCompany);

// GET /api/history  (supports ?limit=20&page=1)
router.get('/history', getHistory);

// GET /api/history/:id
router.get('/history/:id', validateObjectId, getReportById);

// DELETE /api/history/:id
router.delete('/history/:id', validateObjectId, deleteReport);

export default router;

import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { HumanMessage, SystemMessage } from '@langchain/core/messages';
import axios from 'axios';
import { generateMockReport } from './mockService.js';
import { logger } from '../utils/logger.js';

// ─────────────────────────────────────────────
// CONFIG
// ─────────────────────────────────────────────

// Verified available model from API key probe
const GEMINI_MODEL = 'gemini-2.0-flash';

// ─────────────────────────────────────────────
// STEP 2: TAVILY MULTI-TOPIC INTELLIGENCE GATHER
// ─────────────────────────────────────────────

async function tavilySearch(query, tavilyKey) {
  try {
    const res = await axios.post(
      'https://api.tavily.com/search',
      {
        api_key: tavilyKey,
        query,
        search_depth: 'advanced',
        max_results: 4,
        include_answer: false,
      },
      { timeout: 12000 }
    );
    return res.data.results || [];
  } catch (err) {
    logger.warn(`[Tavily] Query failed: "${query.slice(0, 60)}" — ${err.message}`);
    return [];
  }
}

async function gatherIntelligence(companyName, tavilyKey) {
  logger.step(`[Agent Step 2] Launching 12 parallel Tavily queries for: ${companyName}`);

  const queries = {
    companyOverview: `${companyName} company overview business segments operations 2025`,
    industry:        `${companyName} industry sector market size trends outlook 2025 2026`,
    businessModel:   `${companyName} business model revenue streams monetization strategy`,
    revenue:         `${companyName} annual revenue earnings growth rate quarterly results 2024 2025`,
    profitability:   `${companyName} net profit margin EBITDA operating income profitability`,
    debt:            `${companyName} total debt balance sheet liabilities debt-to-equity ratio`,
    cashFlow:        `${companyName} free cash flow operating cash flow capital expenditure 2025`,
    competitors:     `${companyName} main competitors market share comparison landscape`,
    marketPosition:  `${companyName} market position brand valuation market capitalization`,
    recentNews:      `${companyName} latest news announcements 2025`,
    growthDrivers:   `${companyName} growth drivers catalysts expansion opportunities`,
    risks:           `${companyName} risks regulatory headwinds threats challenges 2025`,
  };

  const entries = Object.entries(queries);
  const results = await Promise.all(
    entries.map(([key, q]) =>
      tavilySearch(q, tavilyKey).then(hits => [key, hits])
    )
  );

  const intelligence = {};
  for (const [key, hits] of results) {
    intelligence[key] = hits.length
      ? hits.map(h => `• [${h.title}] (${h.url})\n  ${(h.content || '').slice(0, 500)}`).join('\n\n')
      : 'No live data retrieved for this category.';
  }

  // Deduplicated sources list
  intelligence._sources = results
    .flatMap(([, hits]) => hits.map(h => ({ title: h.title, url: h.url, source: new URL(h.url).hostname.replace('www.', '') })))
    .filter((v, i, arr) => arr.findIndex(x => x.url === v.url) === i);

  logger.step(`[Agent Step 2] Intelligence gathered. Sources found: ${intelligence._sources.length}`);
  return intelligence;
}

// ─────────────────────────────────────────────
// STEP 3: GEMINI ANALYST SYSTEM PROMPT
// ─────────────────────────────────────────────

const SYSTEM_PROMPT = `You are Dr. Maya Krishnan, a Senior Managing Director at a global equity research firm with 20+ years of experience covering Asian and US equity markets.

Your methodology:
- You do NOT summarize. You ANALYZE and EVALUATE.
- You form independent assessments based on evidence.
- You explain every score with 2-3 sentences of evidence-backed reasoning.
- You are direct, data-driven, and calibrated — not optimistic without cause.

Scoring dimensions (each 0–100):
- revenueGrowthScore:        Historical CAGR, growth acceleration/deceleration, quality of growth
- financialStabilityScore:   Debt levels, interest coverage, cash runway, free cash flow
- competitiveAdvantageScore: Moats — brand, switching costs, network effects, IP, scale
- industryOutlookScore:      TAM trajectory, tailwinds/headwinds, regulatory environment
- innovationScore:           R&D spend, patent activity, product pipeline, disruption potential
- newsSentimentScore:        Quality and direction of recent news — lawsuits, partnerships, launches
- riskFactorScore:           INVERSE score. 100 = very low risk. 0 = existential risk
- growthPotentialScore:      Addressable market runway, execution track record, catalysts

Final investmentScore (weighted composite):
  revenueGrowthScore        × 0.15
  financialStabilityScore   × 0.20
  competitiveAdvantageScore × 0.20
  industryOutlookScore      × 0.10
  innovationScore           × 0.10
  newsSentimentScore        × 0.05
  riskFactorScore           × 0.10
  growthPotentialScore      × 0.10

Decision rules (apply STRICTLY, server also enforces this):
  investmentScore ≥ 80 → recommendation = "Invest"
  investmentScore 60–79 → recommendation = "Consider"
  investmentScore < 60  → recommendation = "Pass"

Return ONLY raw valid JSON. No markdown. No preamble. No explanation outside the JSON.`;

function buildPrompt(companyName, intel) {
  return `Conduct a full equity research evaluation for: ${companyName}

=== INTELLIGENCE GATHERED VIA TAVILY WEB SEARCH ===

[COMPANY OVERVIEW]
${intel.companyOverview}

[INDUSTRY & SECTOR]
${intel.industry}

[BUSINESS MODEL]
${intel.businessModel}

[REVENUE & GROWTH]
${intel.revenue}

[PROFITABILITY]
${intel.profitability}

[DEBT & BALANCE SHEET]
${intel.debt}

[CASH FLOW]
${intel.cashFlow}

[COMPETITORS & MARKET SHARE]
${intel.competitors}

[MARKET POSITION & BRAND]
${intel.marketPosition}

[RECENT NEWS & SENTIMENT]
${intel.recentNews}

[GROWTH DRIVERS & CATALYSTS]
${intel.growthDrivers}

[RISKS & HEADWINDS]
${intel.risks}

=== REQUIRED JSON OUTPUT ===

{
  "companyName": "<full name and ticker if public>",
  "recommendation": "<Invest|Consider|Pass>",
  "investmentScore": <0-100 weighted composite>,
  "confidenceScore": <0-100 based on data completeness>,

  "dimensionScores": {
    "revenueGrowthScore": <0-100>,
    "revenueGrowthAnalysis": "<2-3 sentence evidence-backed evaluation>",
    "financialStabilityScore": <0-100>,
    "financialStabilityAnalysis": "<2-3 sentence evaluation>",
    "competitiveAdvantageScore": <0-100>,
    "competitiveAdvantageAnalysis": "<2-3 sentence moat evaluation>",
    "industryOutlookScore": <0-100>,
    "industryOutlookAnalysis": "<2-3 sentence industry evaluation>",
    "innovationScore": <0-100>,
    "innovationAnalysis": "<2-3 sentence innovation evaluation>",
    "newsSentimentScore": <0-100>,
    "newsSentimentAnalysis": "<2-3 sentence news sentiment evaluation>",
    "riskFactorScore": <0-100>,
    "riskFactorAnalysis": "<2-3 sentence risk evaluation>",
    "growthPotentialScore": <0-100>,
    "growthPotentialAnalysis": "<2-3 sentence growth runway evaluation>"
  },

  "companyOverview":  "<2-3 sentences: what company does, scale, key segments>",
  "businessModel":    "<how company makes money — products, channels, monetization>",
  "industry":         "<industry context — size, tailwinds, headwinds, dynamics>",
  "financialHealth":  "<synthesis of revenue, margins, FCF, debt, returns>",

  "strengths": ["<evidence-backed strength 1>", "<strength 2>", "<strength 3>"],
  "weaknesses": ["<evidence-backed weakness 1>", "<weakness 2>", "<weakness 3>"],

  "competitors": [
    { "name": "<Competitor 1>", "marketCap": "<est. cap>", "strengths": "<why they are a threat>" },
    { "name": "<Competitor 2>", "marketCap": "<est. cap>", "strengths": "<why they are a threat>" }
  ],

  "recentNews": [
    { "title": "<headline>", "source": "<publication>", "snippet": "<analytical impact assessment>", "url": "<url>" }
  ],

  "riskAnalysis":    "<full risk narrative — regulatory, macro, competitive, execution, geopolitical>",
  "growthPotential": "<full growth narrative — TAM, expansion vectors, pipeline, catalysts>",
  "reasoning":       "<final synthesis: why this recommendation, what pushed score up/down, what would change rating>"
}`;
}

// ─────────────────────────────────────────────
// MAIN EXPORT
// ─────────────────────────────────────────────

export const performResearch = async (companyName) => {
  const geminiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_GENAI_API_KEY;
  const tavilyKey = process.env.TAVILY_API_KEY;

  // ── Step 1 ──
  logger.step(`\n${'═'.repeat(60)}`);
  logger.step(`[Agent Step 1] Research request: "${companyName}"`);
  logger.step(`${'═'.repeat(60)}`);

  if (!geminiKey) {
    logger.warn('[Agent Step 1] GEMINI_API_KEY missing — sandbox mock mode.');
    return generateMockReport(companyName);
  }

  // ── Step 2: Gather intelligence ──
  let intelligence = {};
  if (tavilyKey) {
    intelligence = await gatherIntelligence(companyName, tavilyKey);
  } else {
    logger.warn('[Agent Step 2] TAVILY_API_KEY missing — Gemini will rely on training data only.');
    const cats = ['companyOverview','industry','businessModel','revenue','profitability',
      'debt','cashFlow','competitors','marketPosition','recentNews','growthDrivers','risks'];
    cats.forEach(c => { intelligence[c] = 'No live search data. Evaluate using training knowledge.'; });
    intelligence._sources = [];
  }

  // ── Step 3: Gemini evaluation ──
  try {
    logger.step(`[Agent Step 3] Sending to Gemini (${GEMINI_MODEL}) for equity analysis...`);

    const model = new ChatGoogleGenerativeAI({
      apiKey:          geminiKey,
      modelName:       GEMINI_MODEL,
      maxOutputTokens: 4096,
      temperature:     0.15,
    });

    const response = await model.invoke([
      new SystemMessage(SYSTEM_PROMPT),
      new HumanMessage(buildPrompt(companyName, intelligence)),
    ]);

    let raw = (typeof response.content === 'string' ? response.content : JSON.stringify(response.content))
      .trim()
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();

    let report;
    try {
      report = JSON.parse(raw);
    } catch {
      logger.error('[Agent Step 3] JSON parse failed. Raw output:\n' + raw.slice(0, 400));
      throw new Error('Gemini returned malformed JSON.');
    }

    // Enforce decision rule server-side (overrides LLM if it miscalculates)
    const score = Number(report.investmentScore) || 0;
    report.recommendation = score >= 80 ? 'Invest' : score >= 60 ? 'Consider' : 'Pass';

    // Attach live sources if LLM left recentNews empty
    if (!report.recentNews?.length) {
      report.recentNews = (intelligence._sources || []).slice(0, 3).map(s => ({
        title:   s.title,
        source:  s.source,
        snippet: 'Retrieved via live Tavily web search.',
        url:     s.url,
      }));
    }

    logger.step(`[Agent Step 3] Analysis complete → Score: ${score} → ${report.recommendation}`);
    return report;

  } catch (err) {
    logger.error(`[Agent Step 3] Gemini failed: ${err.message}`);
    logger.warn('[Agent Step 3] Falling back to sandbox mock.');
    return generateMockReport(companyName);
  }
};

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { connectDB } from './config/db.js';
import analysisRoutes from './routes/analysisRoutes.js';
import { errorHandler } from './middleware/errorHandler.js';
import { logger } from './utils/logger.js';

// Load environment variables first
dotenv.config();

const app  = express();
const PORT = process.env.PORT || 5001;

// ── Middleware ──────────────────────────────
app.use(cors());
app.use(express.json());

// ── Database ────────────────────────────────
connectDB();

// ── Routes ──────────────────────────────────
// POST   /api/analyze
// GET    /api/history
// GET    /api/history/:id
// DELETE /api/history/:id
app.use('/api', analysisRoutes);

// ── Health Check ────────────────────────────
app.get('/health', (req, res) => {
