import axios from 'axios';
import type { ResearchReport } from '../types';

const apiClient = axios.create({
  baseURL: '/api',
  headers: {
    'Content-Type': 'application/json',
  },
});

interface ApiResponse<T> {
  success: boolean;
  data: T;
  error?: string;
  details?: any;
}

interface PaginatedHistory {
  reports: ResearchReport[];
  pagination: {
    total: number;
    page: number;
    limit: number;
    totalPages: number;
  };
}

export const analyzeCompany = async (companyName: string): Promise<ResearchReport> => {
  const response = await apiClient.post<ApiResponse<ResearchReport>>('/analyze', { companyName });
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to analyze company');
  }
  return response.data.data;
};

export const getHistory = async (page = 1, limit = 20): Promise<ResearchReport[]> => {
  const response = await apiClient.get<ApiResponse<PaginatedHistory>>('/history', {
    params: { page, limit }
  });
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to fetch history');
  }
  return response.data.data.reports;
};

export const getReportById = async (id: string): Promise<ResearchReport> => {
  const response = await apiClient.get<ApiResponse<ResearchReport>>(`/history/${id}`);
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to fetch report');
  }
  return response.data.data;
};

export const deleteReport = async (id: string): Promise<void> => {
  const response = await apiClient.delete<ApiResponse<{ message: string }>>(`/history/${id}`);
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to delete report');
  }
};

