@import "tailwindcss";

:root {
  color-scheme: dark;
  background-color: #0b0f19;
  color: #f3f4f6;
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
}

body {
  margin: 0;
  padding: 0;
  min-height: 100vh;
  background: radial-gradient(circle at 50% 0%, #1e1b4b 0%, #0f172a 50%, #020617 100%);
  background-attachment: fixed;
  overflow-x: hidden;
  transition: background 0.3s ease, color 0.3s ease;
}

#root {
  width: 100%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* ── Glassmorphism scrollbar ── */
::-webkit-scrollbar {
  width: 8px;
}
::-webkit-scrollbar-track {
  background: rgba(15, 23, 42, 0.5);
}
::-webkit-scrollbar-thumb {
  background: rgba(99, 102, 241, 0.3);
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(99, 102, 241, 0.6);
}

/* ── Glass card styling helper ── */
.glass-panel {
  background: rgba(15, 23, 42, 0.45);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.37);
  transition: background 0.3s ease, border-color 0.3s ease;
}

.glass-panel-glow {
  background: rgba(15, 23, 42, 0.6);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(99, 102, 241, 0.2);
  box-shadow: 0 0 25px rgba(99, 102, 241, 0.1);
}

/* ── Light Mode Overrides ── */
body.light-theme {
  color-scheme: light;
  background: #f8fafc; /* slate-50 */
  color: #0f172a;
}
body.light-theme .glass-panel {
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid rgba(0, 0, 0, 0.05);
  box-shadow: 0 4px 20px 0 rgba(0, 0, 0, 0.05);
}
body.light-theme .glass-panel-glow {
  background: rgba(255, 255, 255, 0.95);
  border: 1px solid rgba(99, 102, 241, 0.4);
  box-shadow: 0 0 20px rgba(99, 102, 241, 0.15);
}
body.light-theme .text-slate-200, 
body.light-theme .text-slate-300, 
body.light-theme .text-slate-400,
body.light-theme .text-white {
  color: #1e293b !important;
}
body.light-theme .text-slate-500,
body.light-theme .text-slate-600 {
  color: #475569 !important;
}
body.light-theme .bg-slate-900,
body.light-theme .bg-slate-950,
body.light-theme .bg-slate-950\/40 {
  background-color: #f1f5f9 !important;
  border-color: #e2e8f0 !important;
}
body.light-theme circle.stroke-slate-800 {
  stroke: #cbd5e1 !important;
}

/* ── Print / PDF Export Styles ── */
@media print {
  body {
    background: white !important;
    color: black !important;
  }
  .glass-panel, .glass-panel-glow {
    background: white !important;
    backdrop-filter: none !important;
    border: 1px solid #ccc !important;
    box-shadow: none !important;
    page-break-inside: avoid;
    break-inside: avoid;
    margin-bottom: 1rem;
  }
  /* Hide elements we don't want in PDF */
  .no-print, header, aside, .sidebar-container {
    display: none !important;
  }
  /* Force text colors to be legible on paper */
  .text-white, .text-slate-200, .text-slate-300, .text-slate-400 {
    color: #111 !important;
  }
  .bg-slate-900, .bg-slate-950 {
    background-color: #f5f5f5 !important;
  }
}

import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'dark' | 'light';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('investiq_theme');
    if (saved === 'light' || saved === 'dark') return saved;
    // Default to dark since it's the original premium look
    return 'dark';
  });

  useEffect(() => {
    localStorage.setItem('investiq_theme', theme);
    if (theme === 'light') {
      document.body.classList.add('light-theme');
    } else {
      document.body.classList.remove('light-theme');
    }
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
};

