// ─────────────────────────────────────────────
// MAIN EXPORT
// ─────────────────────────────────────────────

export const performResearch = async (companyName) => {
  const geminiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_GENAI_API_KEY;
  const tavilyKey = process.env.TAVILY_API_KEY;

  // ── Step 1 ──
  logger.step(`\n${'═'.repeat(60)}`);
  logger.step(`[Agent Step 1] Research request: "${companyName}"`);
  logger.step(`${'═'.repeat(60)}`);

  if (!geminiKey) {
    logger.warn('[Agent Step 1] GEMINI_API_KEY missing — sandbox mock mode.');
    return generateMockReport(companyName);
  }

  // ── Step 2: Gather intelligence ──
  let intelligence = {};
  if (tavilyKey) {
    intelligence = await gatherIntelligence(companyName, tavilyKey);
  } else {
    logger.warn('[Agent Step 2] TAVILY_API_KEY missing — Gemini will rely on training data only.');
    const cats = ['companyOverview','industry','businessModel','revenue','profitability',
      'debt','cashFlow','competitors','marketPosition','recentNews','growthDrivers','risks'];
    cats.forEach(c => { intelligence[c] = 'No live search data. Evaluate using training knowledge.'; });
    intelligence._sources = [];
  }

  // ── Step 3: Gemini evaluation ──
  try {
    logger.step(`[Agent Step 3] Sending to Gemini (${GEMINI_MODEL}) for equity analysis...`);

    const model = new ChatGoogleGenerativeAI({
      apiKey:          geminiKey,
      modelName:       GEMINI_MODEL,
      maxOutputTokens: 4096,
      temperature:     0.15,
    });

    const response = await model.invoke([
      new SystemMessage(SYSTEM_PROMPT),
      new HumanMessage(buildPrompt(companyName, intelligence)),
    ]);

    let raw = (typeof response.content === 'string' ? response.content : JSON.stringify(response.content))
      .trim()
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();

    let report;
    try {
      report = JSON.parse(raw);
    } catch {
      logger.error('[Agent Step 3] JSON parse failed. Raw output:\n' + raw.slice(0, 400));
      throw new Error('Gemini returned malformed JSON.');
    }

    // Enforce decision rule server-side (overrides LLM if it miscalculates)
    const score = Number(report.investmentScore) || 0;
    report.recommendation = score >= 80 ? 'Invest' : score >= 60 ? 'Consider' : 'Pass';

    // Attach live sources if LLM left recentNews empty
    if (!report.recentNews?.length) {
      report.recentNews = (intelligence._sources || []).slice(0, 3).map(s => ({
        title:   s.title,
        source:  s.source,
        snippet: 'Retrieved via live Tavily web search.',
        url:     s.url,
      }));
    }

    logger.step(`[Agent Step 3] Analysis complete → Score: ${score} → ${report.recommendation}`);
    return report;

  } catch (err) {
    logger.error(`[Agent Step 3] Gemini failed: ${err.message}`);
    logger.warn('[Agent Step 3] Falling back to sandbox mock.');
    return generateMockReport(companyName);
  }
};

