import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react(), tailwindcss()],
  server: {
    port: 3000,
    proxy: {
      '/api': {
        target: 'http://localhost:5001',
        changeOrigin: true,
      }
    }
  }
})

import axios from 'axios';

const apiClient = axios.create({
  baseURL: '/api',
  headers: {
    'Content-Type': 'application/json',
  },
});

export const analyzeCompany = async (companyName) => {
  const response = await apiClient.post('/analyze', { companyName });
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to analyze company');
  }
  return response.data.data;
};

export const getHistory = async (page = 1, limit = 20) => {
  const response = await apiClient.get('/history', {
    params: { page, limit }
  });
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to fetch history');
  }
  return response.data.data.reports;
};

export const getReportById = async (id) => {
  const response = await apiClient.get(`/history/${id}`);
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to fetch report');
  }
  return response.data.data;
};

export const deleteReport = async (id) => {
  const response = await apiClient.delete(`/history/${id}`);
  if (!response.data.success) {
    throw new Error(response.data.error || 'Failed to delete report');
  }
};

import { createContext, useContext, useEffect, useState } from 'react';

const ThemeContext = createContext(undefined);

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem('investiq_theme');
    if (saved === 'light' || saved === 'dark') return saved;
    // Default to dark since it's the original premium look
    return 'dark';
  });

  useEffect(() => {
    localStorage.setItem('investiq_theme', theme);
    if (theme === 'light') {
      document.body.classList.add('light-theme');
    } else {
      document.body.classList.remove('light-theme');
    }
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
};

import { useState, useEffect } from 'react';
import { DashboardHeader } from './components/DashboardHeader.jsx';
import { ResearchForm } from './components/ResearchForm.jsx';
import { LoadingState } from './components/LoadingState.jsx';
import { ResearchResults } from './components/ResearchResults.jsx';
import { HistorySidebar } from './components/HistorySidebar.jsx';
import { analyzeCompany, getHistory } from './services/api.js';
import { Sparkles, Brain, Info, RefreshCw } from 'lucide-react';
import { Toaster, toast } from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from './contexts/ThemeContext.jsx';

function App() {
  const [history, setHistory] = useState([]);
  const [selectedReport, setSelectedReport] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  const { theme } = useTheme();

  useEffect(() => {
    loadHistory();

    const handleKeyDown = (e) => {
      // Cmd/Ctrl + K to focus search is handled in ResearchForm
      // Cmd/Ctrl + C to copy report
      if ((e.metaKey || e.ctrlKey) && e.key === 'c' && selectedReport) {
        // Only trigger if user hasn't selected text
        if (window.getSelection()?.toString() === '') {
          e.preventDefault();
          const reportText = `InvestIQ Analysis: ${selectedReport.companyName}\nRecommendation: ${selectedReport.recommendation}\nScore: ${selectedReport.investmentScore}/100`;
          navigator.clipboard.writeText(reportText);
          toast.success('Report summary copied to clipboard!');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedReport]);

  const loadHistory = async () => {
    try {
      const data = await getHistory();
      setHistory(data);
      if (data.length > 0 && !selectedReport) {
        setSelectedReport(data[0]);
      }
    } catch (err) {
      console.warn('Failed to load analysis history:', err);
    }
  };

  const handleResearch = async (companyName) => {
    setIsLoading(true);
    setError(null);
    setSelectedReport(null);

    try {
      const report = await analyzeCompany(companyName);
      setSelectedReport(report);
      // Reload history to include the new report
      await loadHistory();
    } catch (err) {
      console.error(err);
      setError(
        err.response?.data?.error || 
        'An error occurred while compiling research. Ensure backend server is running.'
      );
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen">
      <Toaster 
        position="top-right" 
        toastOptions={{
          style: {
            background: theme === 'dark' ? '#1e293b' : '#ffffff',
            color: theme === 'dark' ? '#f8fafc' : '#0f172a',
            border: theme === 'dark' ? '1px solid rgba(255,255,255,0.1)' : '1px solid rgba(0,0,0,0.1)',
          }
        }} 
      />
      <DashboardHeader />

      <main className="flex-1 p-6 max-w-7xl mx-auto w-full grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Left Column: Form & General Info */}
        <div className="lg:col-span-4 space-y-6">
          <ResearchForm onSearch={handleResearch} isLoading={isLoading} />

          {/* Platform Information Box */}
          <div className="glass-panel p-5 rounded-2xl border border-white/5 bg-indigo-950/5">
            <h4 className="text-sm font-bold text-slate-100 flex items-center gap-2 mb-2">
              <Brain className="w-4.5 h-4.5 text-indigo-400" />
              How the System Works
            </h4>
            <ul className="text-xs text-slate-400 space-y-2">
              <li className="flex items-start gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                <span>Crawls live search data for active stock indicators & market trends.</span>
              </li>
              <li className="flex items-start gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                <span>Aggregates competitor metrics, valuations, and SWOT profiles.</span>
              </li>
              <li className="flex items-start gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 flex-shrink-0" />
                <span>Evaluates growth drivers and parses risks using structured analytical models.</span>
              </li>
            </ul>
          </div>

          {/* History Sidebar - Visible under Search on smaller screens */}
          <div className="block lg:hidden">
            <HistorySidebar
              history={history}
              onSelectReport={setSelectedReport}
              selectedReportId={selectedReport?._id}
            />
          </div>
        </div>

        {/* Right Column: Output / Loaders / Results */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          {isLoading && <LoadingState />}

          {error && (
            <motion.div 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="glass-panel p-6 rounded-2xl border border-rose-500/20 bg-rose-500/5 text-slate-100 flex items-start justify-between gap-3.5"
            >
              <div className="flex items-start gap-3.5">
                <Info className="w-6 h-6 text-rose-400 flex-shrink-0 mt-0.5" />
                <div>
                  <h4 className="font-bold text-rose-400">Research Compilation Failed</h4>
                  <p className="text-sm text-slate-350 mt-1">{error}</p>
                </div>
              </div>
              <button 
                onClick={() => handleResearch('Retry')} 
                className="flex items-center gap-2 px-3 py-1.5 text-xs font-bold text-rose-400 bg-rose-500/10 border border-rose-500/20 rounded-lg hover:bg-rose-500/20 transition-colors"
              >
                <RefreshCw className="w-3.5 h-3.5" /> Retry
              </button>
            </motion.div>
          )}

          <AnimatePresence mode="wait">
            {!isLoading && !error && selectedReport && (
              <motion.div
                key={selectedReport._id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -20 }}
                transition={{ duration: 0.4, ease: "easeOut" }}
              >
                <ResearchResults report={selectedReport} />
              </motion.div>
            )}
          </AnimatePresence>

          {!isLoading && !error && !selectedReport && (
            <motion.div 
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className="glass-panel p-8 rounded-2xl border border-white/5 shadow-xl flex flex-col items-center justify-center min-h-[400px] text-center"
            >
              <div className="p-4 bg-slate-900 border border-slate-800 rounded-full mb-4 shadow-lg shadow-indigo-500/10">
                <Sparkles className="w-8 h-8 text-indigo-400" />
              </div>
              <h3 className="text-base font-bold text-slate-200 mb-2">No Active Analysis</h3>
              <p className="text-sm text-slate-400 max-w-sm">
                Press <kbd className="px-1.5 py-0.5 bg-slate-800 border border-slate-700 rounded text-xs text-slate-300 font-mono">⌘K</kbd> to search for a company, or select a report from history.
              </p>
            </motion.div>
          )}
        </div>

        {/* Desktop History Sidebar (Fixed in layout) */}
        <div className="hidden lg:block lg:col-span-12 mt-6">
          <HistorySidebar
            history={history}
            onSelectReport={setSelectedReport}
            selectedReportId={selectedReport?._id}
          />
        </div>
      </main>
    </div>
  );
}

export default App;

import { TrendingUp, Cpu, Moon, Sun } from 'lucide-react';
import { useTheme } from '../contexts/ThemeContext.jsx';

export const DashboardHeader = () => {
  const { theme, toggleTheme } = useTheme();

  return (
    <header className="glass-panel sticky top-0 z-50 px-6 py-4 flex items-center justify-between border-b border-white/5">
      <div className="flex items-center gap-3">
        <div className="p-2.5 bg-indigo-500/10 border border-indigo-500/25 rounded-xl shadow-inner shadow-indigo-500/20">
          <TrendingUp className="w-6 h-6 text-indigo-400" />
        </div>
        <div>
          <h1 className="text-xl font-bold tracking-tight text-white m-0 flex items-center gap-2">
            InvestIQ <span className="px-2 py-0.5 text-[10px] tracking-wide uppercase font-semibold bg-indigo-600/20 text-indigo-400 border border-indigo-500/30 rounded-md">Pro</span>
          </h1>
          <p className="text-xs text-slate-400">Fundamental Investment Analytics</p>
        </div>
      </div>

      <div className="flex items-center gap-4">
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-xs font-medium text-emerald-400">
          <Cpu className="w-3.5 h-3.5" />
          <span>Active Connection</span>
        </div>
        <button
          onClick={toggleTheme}
          className="p-2 rounded-xl bg-slate-800/50 hover:bg-slate-700/50 border border-slate-700 transition-colors text-slate-300"
          title={`Switch to ${theme === 'dark' ? 'Light' : 'Dark'} Mode`}
        >
          {theme === 'dark' ? <Sun className="w-4 h-4" /> : <Moon className="w-4 h-4" />}
        </button>
      </div>
    </header>
  );
};

import { useState, useRef, useEffect } from 'react';
import { Search, Sparkles } from 'lucide-react';

const POPULAR_COMPANIES = ['Apple (AAPL)', 'Microsoft (MSFT)', 'Tesla (TSLA)', 'NVIDIA (NVDA)', 'Infosys', 'Reliance'];

export const ResearchForm = ({ onSearch, isLoading }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    const handleKeyDown = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim());
    }
  };

  const handleQuickSelect = (name) => {
    if (!isLoading) {
      setQuery(name);
      onSearch(name);
    }
  };

  return (
    <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl">
      <h2 className="text-lg font-semibold text-slate-100 mb-2 flex items-center gap-2">
        <Sparkles className="w-5 h-5 text-indigo-400" />
        Analyze Investment Opportunity
      </h2>
      <p className="text-sm text-slate-400 mb-6">
        Enter a company name or ticker. Our autonomous research agent will scan the live web, compile financials, assess risks, and generate an institutional-grade investment recommendation.
      </p>

      <form onSubmit={handleSubmit} className="relative mb-6">
        <div className="relative flex items-center">
          <Search className="absolute left-4 w-5 h-5 text-slate-400" />
          <input
            ref={inputRef}
            type="text"
            placeholder="e.g., Apple Inc., NVIDIA, Super Micro Computer..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            disabled={isLoading}
            className="w-full pl-12 pr-44 py-4 rounded-xl bg-slate-950/60 border border-slate-800 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 transition-all text-base disabled:opacity-50"
          />
          <div className="absolute right-28 hidden sm:flex items-center gap-1 opacity-50 pointer-events-none">
            <kbd className="px-1.5 py-0.5 bg-slate-800 border border-slate-700 rounded text-[10px] text-slate-300 font-mono">⌘</kbd>
            <kbd className="px-1.5 py-0.5 bg-slate-800 border border-slate-700 rounded text-[10px] text-slate-300 font-mono">K</kbd>
          </div>
          <button
            type="submit"
            disabled={!query.trim() || isLoading}
            className="absolute right-2 px-5 py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-medium text-sm transition-all shadow-lg shadow-indigo-600/20 active:scale-95 disabled:opacity-50 disabled:scale-100 disabled:shadow-none flex items-center gap-1.5"
          >
            {isLoading ? 'Researching...' : 'Analyze'}
          </button>
        </div>
      </form>

      <div>
        <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider block mb-2.5">
          Popular Queries
        </span>
        <div className="flex flex-wrap gap-2">
          {POPULAR_COMPANIES.map((company) => (
            <button
              key={company}
              type="button"
              onClick={() => handleQuickSelect(company)}
              disabled={isLoading}
              className="px-3.5 py-1.5 rounded-lg text-xs font-medium bg-slate-900 border border-slate-800 text-slate-300 hover:border-slate-700 hover:bg-slate-850 hover:text-white transition-all disabled:opacity-50 cursor-pointer"
            >
              {company}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

import { History, ChevronRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const HistorySidebar = ({ history, onSelectReport, selectedReportId }) => {
  const getBadgeStyle = (rec) => {
    switch (rec) {
      case 'Invest':
        return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20';
      case 'Consider':
        return 'bg-amber-500/10 text-amber-400 border-amber-500/20';
      case 'Pass':
        return 'bg-rose-500/10 text-rose-400 border-rose-500/20';
      default:
        return 'bg-slate-500/10 text-slate-400 border-slate-500/20';
    }
  };

  return (
    <div className="glass-panel p-6 rounded-2xl border border-white/5 shadow-xl flex flex-col h-full">
      <h3 className="text-base font-bold text-slate-100 mb-4 flex items-center gap-2">
        <History className="w-5 h-5 text-indigo-400" />
        Recent Searches
      </h3>

      {history.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-center p-4">
          <p className="text-sm text-slate-500">No past analyses found.</p>
          <p className="text-xs text-slate-600 mt-1">Start by searching a company name above.</p>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto space-y-3 pr-1">
          <AnimatePresence>
            {history.map((report, index) => {
              const isSelected = report._id === selectedReportId;
              return (
                <motion.button
                  key={report._id}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, scale: 0.9 }}
                  transition={{ duration: 0.2, delay: index * 0.05 }}
                  onClick={() => onSelectReport(report)}
                  className={`w-full text-left p-3.5 rounded-xl border transition-all flex items-center justify-between group cursor-pointer ${
                    isSelected 
                      ? 'bg-indigo-600/10 border-indigo-500/40' 
                      : 'bg-slate-900/40 border-slate-800 hover:border-slate-700 hover:bg-slate-900/60'
                  }`}
                >
                  <div className="max-w-[80%]">
                    <h4 className="text-sm font-semibold text-slate-200 group-hover:text-indigo-400 transition-colors truncate">
                      {report.companyName}
                    </h4>
                    <div className="flex items-center gap-2 mt-2">
                      <span className={`px-2 py-0.5 text-[10px] uppercase font-bold rounded border ${getBadgeStyle(report.recommendation)}`}>
                        {report.recommendation}
                      </span>
                      <span className="text-[10px] text-slate-500 font-mono">Score: {report.investmentScore}</span>
                    </div>
                  </div>
                  <ChevronRight className="w-4 h-4 text-slate-500 group-hover:text-indigo-400 transition-colors" />
                </motion.button>
              );
            })}
          </AnimatePresence>
        </div>
      )}
    </div>
  );
};

import { useEffect, useState } from 'react';
import { Loader2, Globe, ShieldAlert, AlertTriangle, Compass, CheckCircle2 } from 'lucide-react';

const RESEARCH_STEPS = [
  { id: 0, label: 'Initializing Research Agent', subLabel: 'Configuring Gemini LLM and research parameters...', icon: Compass },
  { id: 1, label: 'Crawling Web for Live Market Intelligence', subLabel: 'Triggering Tavily search crawler across financial journals and news portals...', icon: Globe },
  { id: 2, label: 'Analyzing Financial Indicators & Cash Flows', subLabel: 'Parsing balance sheets, cash flows, and operating margins...', icon: AlertTriangle },
  { id: 3, label: 'Running SWOT & Risk Assessment', subLabel: 'Synthesizing strengths, weaknesses, threats, and competitor landscapes...', icon: ShieldAlert },
  { id: 4, label: 'Finalizing Investment Recommendation', subLabel: 'Compiling thesis score and formatting structured report...', icon: CheckCircle2 }
];

export const LoadingState = () => {
  const [activeStep, setActiveStep] = useState(0);

  useEffect(() => {
    const intervals = [2500, 3500, 3000, 2500];
    let currentStep = 0;

    const runNext = () => {
      if (currentStep < RESEARCH_STEPS.length - 1) {
        currentStep += 1;
        setActiveStep(currentStep);
        setTimeout(runNext, intervals[currentStep - 1] || 2000);
      }
    };

    const timer = setTimeout(runNext, intervals[0]);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="space-y-6 animate-pulse">
      {/* Skeleton Header */}
      <div className="glass-panel p-6 rounded-2xl border border-white/5 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="space-y-3">
          <div className="h-5 w-48 bg-slate-800/50 rounded-md"></div>
          <div className="h-8 w-64 bg-slate-800/80 rounded-md"></div>
          <div className="h-3 w-72 bg-slate-800/40 rounded-md"></div>
        </div>
        <div className="flex gap-2">
          <div className="w-10 h-10 bg-slate-800/50 rounded-lg"></div>
          <div className="w-10 h-10 bg-slate-800/50 rounded-lg"></div>
          <div className="w-10 h-10 bg-slate-800/50 rounded-lg"></div>
        </div>
      </div>

      {/* Skeleton Top Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[1, 2, 3].map(i => (
          <div key={i} className="glass-panel p-6 rounded-2xl border border-white/5 flex flex-col items-center justify-center min-h-[160px]">
            <div className="h-4 w-24 bg-slate-800/50 rounded-md mb-6"></div>
            <div className="w-20 h-20 bg-slate-800/30 rounded-full border-4 border-slate-800/50"></div>
          </div>
        ))}
        <div className="glass-panel p-6 rounded-2xl border border-white/5 lg:col-span-1 md:col-span-2">
           <div className="h-4 w-24 bg-slate-800/50 rounded-md mb-4"></div>
           <div className="space-y-2">
             <div className="h-3 w-full bg-slate-800/40 rounded-md"></div>
             <div className="h-3 w-full bg-slate-800/40 rounded-md"></div>
             <div className="h-3 w-3/4 bg-slate-800/40 rounded-md"></div>
             <div className="h-3 w-5/6 bg-slate-800/40 rounded-md"></div>
           </div>
        </div>
      </div>

      {/* Center Agent Status overlaying skeleton */}
      <div className="relative">
